import 'asset.dart';
import 'recency_index.dart';

class AssetCache {
  final int capacity;
  final Map<String, Asset> _values = <String, Asset>{};
  final RecencyIndex _recency = RecencyIndex();

  AssetCache(this.capacity) {
    if (capacity < 1) throw ArgumentError.value(capacity, 'capacity');
  }

  Asset? get(String key) {
    final value = _values[key];
    if (value != null) {
      _recency.record(key);
    }
    return value;
  }

  void put(String key, Asset value) {
    _values[key] = value;
    _recency.record(key);
    if (_values.length > capacity) {
      final evicted = _recency.removeOldest();
      if (evicted != null) _values.remove(evicted);
    }
  }

  List<String> get keys => _recency.keys;
}
